  const asksDeployment = /\b(deploy|redeploy|re-?deploy|ship|release|roll\s*out|publish|push\s+to\s+(?:prod|production|live)|go\s+live)\b/.test(normalized);
  if (asksDeployment) {
    return 'image_then_deployment';
